local http = require "resty.http"
local cjson = require "cjson"

local ALLOWED_HOSTS = {
    ["api.example.com"] = true,
    ["webhook.example.com"] = true,
    ["external-service.com"] = true,
}

local function is_private_ip(ip)
    if not ip then
        return true
    end
    
    local octets = {}
    for octet in string.gmatch(ip, "(%d+)") do
        table.insert(octets, tonumber(octet))
    end
    
    if #octets ~= 4 then
        return true
    end
    
    local o1, o2, o3, o4 = octets[1], octets[2], octets[3], octets[4]
    
    if o1 == 127 then return true end
    if o1 == 10 then return true end
    if o1 == 172 and o2 >= 16 and o2 <= 31 then return true end
    if o1 == 192 and o2 == 168 then return true end
    if o1 == 169 and o2 == 254 then return true end
    if o1 == 0 then return true end
    if o1 >= 224 then return true end
    if o1 == 100 and o2 >= 64 and o2 <= 127 then return true end
    if o1 == 198 and (o2 == 18 or o2 == 19) then return true end
    if o1 == 192 and o2 == 0 and (o3 == 0 or o3 == 2) then return true end
    if o1 == 198 and o2 == 51 and o3 == 100 then return true end
    if o1 == 203 and o2 == 0 and o3 == 113 then return true end
    if o1 == 255 and o2 == 255 and o3 == 255 and o4 == 255 then return true end
    
    return false
end

local function validate_and_resolve_host(host)
    if not host or host == "" then
        return nil, "Empty host"
    end
    
    if not ALLOWED_HOSTS[host] then
        return nil, "Host not in allowlist"
    end
    
    local resolver = require "resty.dns.resolver"
    local r, err = resolver:new{
        nameservers = {"8.8.8.8", "8.8.4.4"},
        retrans = 2,
        timeout = 2000,
    }
    
    if not r then
        return nil, "Failed to create resolver: " .. (err or "unknown")
    end
    
    local answers, err = r:query(host, {qtype = r.TYPE_A})
    if not answers or answers.errcode then
        return nil, "DNS resolution failed: " .. (err or answers.errstr or "unknown")
    end
    
    for _, ans in ipairs(answers) do
        if ans.address then
            if is_private_ip(ans.address) then
                return nil, "Resolved to private IP: " .. ans.address
            end
        end
    end
    
    return true
end

local function parse_url(url)
    local pattern = "^(https?)://([^:/]+):?(%d*)(.*)$"
    local scheme, host, port, path = string.match(url, pattern)
    
    if not scheme or not host then
        return nil, "Invalid URL format"
    end
    
    return {
        scheme = scheme,
        host = host,
        port = port ~= "" and tonumber(port) or (scheme == "https" and 443 or 80),
        path = path ~= "" and path or "/"
    }
end

local target_url = ngx.var.arg_url

if not target_url or target_url == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "Missing url parameter"}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local parsed, err = parse_url(target_url)
if not parsed then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say(cjson.encode({error = "Invalid URL: " .. err}))
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local ok, err = validate_and_resolve_host(parsed.host)
if not ok then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say(cjson.encode({error = "Forbidden destination: " .. err}))
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

local httpc = http.new()
httpc:set_timeout(5000)

local res, err = httpc:request_uri(target_url, {
    method = ngx.var.request_method,
    body = ngx.req.get_body_data(),
    headers = {
        ["Content-Type"] = ngx.var.content_type,
        ["User-Agent"] = "OpenResty-Webhook-Proxy/1.0"
    },
    ssl_verify = true,
    keepalive_timeout = 60000,
    keepalive_pool = 10,
    max_redirects = 0
})

if not res then
    ngx.status = ngx.HTTP_BAD_GATEWAY
    ngx.say(cjson.encode({error = "Request failed: " .. (err or "unknown")}))
    return ngx.exit(ngx.HTTP_BAD_GATEWAY)
end

ngx.status = res.status

for k, v in pairs(res.headers) do
    if k ~= "Transfer-Encoding" and k ~= "Connection" then
        ngx.header[k] = v
